export type ParsedSkimInstruction<
  TProgram extends string = typeof CPMM_PROGRAM_ADDRESS,
  TAccountMetas extends readonly AccountMeta[] = readonly AccountMeta[],
> = {
  programAddress: Address<TProgram>;
  accounts: {
    config: TAccountMetas[0];
    pool: TAccountMetas[1];
    admin: TAccountMetas[2];
    authority: TAccountMetas[3];
    vault0: TAccountMetas[4];
    vault1: TAccountMetas[5];
    token0Mint: TAccountMetas[6];
    token1Mint: TAccountMetas[7];
    adminAta0: TAccountMetas[8];
    adminAta1: TAccountMetas[9];
    tokenProgram: TAccountMetas[10];
  };
  data: SkimInstructionData;
};

export function parseSkimInstruction<
  TProgram extends string,
  TAccountMetas extends readonly AccountMeta[],
>(
  instruction: Instruction<TProgram> &
    InstructionWithAccounts<TAccountMetas> &
    InstructionWithData<ReadonlyUint8Array>,
): ParsedSkimInstruction<TProgram, TAccountMetas> {
  if (instruction.accounts.length < 11) {
    throw new SolanaError(
      SOLANA_ERROR__PROGRAM_CLIENTS__INSUFFICIENT_ACCOUNT_METAS,
      {
        actualAccountMetas: instruction.accounts.length,
        expectedAccountMetas: 11,
      },
    );
  }
  let accountIndex = 0;
  const getNextAccount = () => {
    const accountMeta = (instruction.accounts as TAccountMetas)[accountIndex]!;
    accountIndex += 1;
    return accountMeta;
  };
  return {
    programAddress: instruction.programAddress,
    accounts: {
      config: getNextAccount(),
      pool: getNextAccount(),
      admin: getNextAccount(),
      authority: getNextAccount(),
      vault0: getNextAccount(),
      vault1: getNextAccount(),
      token0Mint: getNextAccount(),
      token1Mint: getNextAccount(),
      adminAta0: getNextAccount(),
      adminAta1: getNextAccount(),
      tokenProgram: getNextAccount(),
    },
    data: getSkimInstructionDataDecoder().decode(instruction.data),
  };
}
